  1→/**
  2→ * Chat Area — renders the active chat tab and wires up the tab bar.
  3→ *
  4→ * Tab lifecycle (create, close, restore, labels) is managed by useChatTabs.
  5→ * This component focuses on layout and connecting tabs to SessionPanel.
  6→ */
  7→
  8→import { useMemo, useCallback, useEffect, useRef } from "react";
  9→import type { Dispatch, SetStateAction } from "react";
 10→import { SessionPanel } from "@/features/session";
 11→import type { SessionPanelRef } from "@/features/session";
 12→import { useWorkingSessionIds } from "@/features/session/api/session.queries";
 13→import { useUnreadStore, unreadActions } from "@/features/session/store/unreadStore";
 14→import { WorkspaceEmptyState } from "@/features/session/ui/WorkspaceEmptyState";
 15→import { MainContentTabBar } from "@/features/workspace";
 16→import type { Workspace } from "@/shared/types";
 17→import { useChatTabs } from "./useChatTabs";
 18→
 19→interface ChatAreaProps {
 20→  workspace: Workspace;
 21→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 22→  onCreatePRHandlerChange: (handler: (() => void) | null) => void;
 23→  onSendAgentMessageHandlerChange: Dispatch<
 24→    SetStateAction<((text: string) => Promise<void>) | null>
 25→  >;
 26→  onCollapseChatPanel?: () => void;
 27→}
 28→
 29→export function ChatArea({
 30→  workspace,
 31→  workspaceChatPanelRef,
 32→  onCreatePRHandlerChange,
 33→  onSendAgentMessageHandlerChange,
 34→  onCollapseChatPanel,
 35→}: ChatAreaProps) {
 36→  const {
 37→    tabs,
 38→    activeTabId,
 39→    activeTab,
 40→    closedTabs,
 41→    handleTabChange,
 42→    handleTabClose,
 43→    handleTabAdd,
 44→    handleTabReorder,
 45→    handleTabRestore,
 46→    updateChatTabAgentType,
 47→    markChatTabStarted,
 48→  } = useChatTabs({
 49→    workspaceId: workspace.id,
 50→    activeSessionId: workspace.current_session_id,
 51→  });
 52→
 53→  // Resolve sessionId: tab's own session, falling back to workspace's active session
 54→  const tabSessionId = activeTab?.data?.sessionId || workspace.current_session_id;
 55→
 56→  // Per-tab working status: subscribes to each chat tab's session detail cache
 57→  // so each tab's spinner reflects its own session's status (not the workspace's
 58→  // single session_status which breaks with multiple tabs).
 59→  const chatSessionIds = useMemo(
 60→    () => tabs.filter((t) => t.data?.sessionId).map((t) => t.data!.sessionId!),
 61→    [tabs]
 62→  );
 63→  const workingSessionIds = useWorkingSessionIds(chatSessionIds);
 64→
 65→  // Mark non-active tab sessions as unread when they leave the working set.
 66→  const activeSessionId = activeTab?.data?.sessionId;
 67→  const prevWorkingRef = useRef(workingSessionIds);
 68→  const prevWorkspaceRef = useRef(workspace.id);
 69→  useEffect(() => {
 70→    // Reset on workspace switch — don't compare across workspaces
 71→    if (prevWorkspaceRef.current !== workspace.id) {
 72→      prevWorkspaceRef.current = workspace.id;
 73→      prevWorkingRef.current = workingSessionIds;
 74→      return;
 75→    }
 76→    const prev = prevWorkingRef.current;
 77→    prevWorkingRef.current = workingSessionIds;
 78→    for (const sid of prev) {
 79→      if (!workingSessionIds.has(sid) && sid !== activeSessionId) {
 80→        unreadActions.markUnread(sid);
 81→      }
 82→    }
 83→  }, [workingSessionIds, activeSessionId, workspace.id]);
 84→
 85→  const unreadMap = useUnreadStore((s) => s.unreadSessionIds);
 86→  const unreadSessionIds = useMemo(
 87→    () => new Set(chatSessionIds.filter((sid) => unreadMap[sid])),
 88→    [chatSessionIds, unreadMap]
 89→  );
 90→
 91→  // Wrap tab change to mark the newly-active session as read inline
 92→  const handleTabChangeWithRead = useCallback(
 93→    (tabId: string) => {
 94→      const tab = tabs.find((t) => t.id === tabId);
 95→      if (tab?.data?.sessionId) {
 96→        unreadActions.markRead(tab.data.sessionId);
 97→      }
 98→      handleTabChange(tabId);
 99→    },
100→    [tabs, handleTabChange]
101→  );
102→
103→  return (
104→    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
105→      <MainContentTabBar
106→        tabs={tabs}
107→        activeTabId={activeTabId}
108→        workingSessionIds={workingSessionIds}
109→        unreadSessionIds={unreadSessionIds}
110→        onTabChange={handleTabChangeWithRead}
111→        onTabClose={handleTabClose}
112→        onTabAdd={handleTabAdd}
113→        onTabReorder={handleTabReorder}
114→        closedTabs={closedTabs}
115→        onTabRestore={handleTabRestore}
116→        onCollapseChatPanel={onCollapseChatPanel}
117→      />
118→
119→      <div className="flex min-h-0 flex-1 flex-col overflow-hidden">
120→        {tabSessionId && (
121→          <SessionPanel
122→            key={tabSessionId}
123→            ref={workspaceChatPanelRef}
124→            sessionId={tabSessionId}
125→            workspaceId={workspace.id}
126→            workspacePath={workspace.workspace_path}
127→            workspaceRepoName={workspace.repo_name}
128→            workspaceParentBranch={workspace.git_target_branch}
129→            workspaceDefaultBranch={workspace.git_default_branch}
130→            isFirstSession={workspace.latest_message_sent_at === null}
131→            embedded={true}
132→            initialModel={activeTab?.data?.initialModel}
133→            onAgentTypeChange={(agentType) =>
134→              activeTab && updateChatTabAgentType(activeTab.id, agentType)
135→            }
